describe("DCG Config E2E", () => {
  it("should update config via REST API and receive WebSocket event", async () => {
    // Connect WebSocket
    const ws = await connectWebSocket("/ws");
    await ws.subscribe("system:dcg");

    // Update config via API
    const response = await fetch("/dcg/config", {
      method: "PUT",
      body: JSON.stringify({
        config: {
          enabledPacks: ["core.git"],
          disabledPacks: ["test.e2e"],
          severityModes: { critical: "deny", high: "deny", medium: "warn", low: "log" },
        },
        reason: "E2E test",
      }),
    });

    expect(response.status).toBe(200);

    // Wait for WebSocket event
    const event = await ws.waitForEvent("dcg.config_changed", 5000);
    expect(event.data.reason).toBe("E2E test");

    logger.info({
      testName: "e2e_config_update",
      responseStatus: response.status,
      wsEvent: event,
      correlationId: getCorrelationId(),
    }, "E2E config update with WebSocket notification");

    await ws.close();
  });

  it("should show config history in UI and allow rollback", async () => {
    // Make several config changes
    await fetch("/dcg/packs/test.pack1/enable", { method: "POST" });
    await fetch("/dcg/packs/test.pack2/enable", { method: "POST" });
    await fetch("/dcg/packs/test.pack1/disable", { method: "POST" });

    // Get history
    const historyResponse = await fetch("/dcg/config/history?limit=10");
    const { history } = await historyResponse.json();

    expect(history.length).toBeGreaterThanOrEqual(3);

    // Rollback to first entry
    const rollbackResponse = await fetch(`/dcg/config/rollback/${history[2].id}`, {
      method: "POST",
    });

    expect(rollbackResponse.status).toBe(200);

    logger.info({
      testName: "e2e_history_rollback",
      historyCount: history.length,
      rollbackTo: history[2].id,
      correlationId: getCorrelationId(),
    }, "E2E history and rollback");
  });
});
